(async () => {
  const sleep = ms => new Promise(r => setTimeout(r, ms));
  const letter = (title) => {
    const t = (title||'').toLowerCase();
    if (t.includes('1с') || t.includes('1c')) return 'Добрый день. Три года сопровождаю серверы Windows и Linux, настраивал AD, VPN, резервное копирование и 1С — сейчас работаю сисадмином 1С в штате и на аутсорсе. Живу в Красноярске, готов к офису 5/2. Могу обсудить опыт на собеседовании.';
    if (/помощник|стаж|младш|начинающ|ученик|оператор/.test(t)) return 'Добрый день. Три года сопровождаю серверы Windows и Linux, сети и рабочие места до 150 ПК — AD, VPN, резервное копирование, 1С. Ищу позицию с возможностью роста. Живу в Красноярске, готов к офису 5/2. Могу обсудить на собеседовании.';
    return 'Добрый день. Три года сопровождаю серверы Windows и Linux, сети и рабочие места в организациях до 150 ПК — настраивал AD, VPN, резервное копирование, 1С. Сейчас работаю сисадмином 1С в штате и на аутсорсе. Живу в Красноярске, готов к офису 5/2. Могу обсудить опыт на собеседовании.';
  };
  const title = document.querySelector('h1[data-qa="vacancy-title"], h1')?.innerText?.trim() || '';
  if (/апогей/i.test(document.body.innerText)) return {status:'blocked', title};
  if (/вы откликнулись|отклик отправлен/i.test(document.body.innerText)) return {status:'already', title};
  const findBtn = () => document.querySelector('[data-qa="vacancy-response-link-top"],[data-qa="vacancy-response-link-bottom"]') || [...document.querySelectorAll('button,a')].find(el => /^откликнуться$/i.test((el.innerText||'').trim()));
  let btn = findBtn();
  if (!btn) return {status:'no_button', title};
  btn.click();
  await sleep(1800);
  const ta = document.querySelector('textarea[data-qa="vacancy-response-popup-form-letter-input"], textarea[name="letter"], textarea');
  if (ta) {
    const val = letter(title);
    ta.focus();
    ta.value = val;
    ta.dispatchEvent(new Event('input', {bubbles:true}));
    ta.dispatchEvent(new Event('change', {bubbles:true}));
    await sleep(500);
    const submit = [...document.querySelectorAll('button')].find(b => /^(отправить|откликнуться)$/i.test((b.innerText||'').trim()));
    if (submit && !submit.disabled) submit.click();
    await sleep(1200);
  }
  const body = document.body.innerText;
  if (/отклик отправлен|вы откликнулись/i.test(body)) return {status:'applied', title};
  return {status:'maybe', title};
})()

